+                let reg = self.ops[i].p2;
+                self.ops[i] = VdbeOp {
+                    opcode: Opcode::FusedLiteralResultRow,
+                    p1: lit,
+                    p2: reg,
+                    p3: 0,
+                    p4: P4::None,
+                    p5: 0,
+                };
