+                    opcode: Opcode::Noop,
+                    p1: 0,
+                    p2: 0,
+                    p3: 0,
+                    p4: P4::None,
+                    p5: 0,
+                };
+                fused += 1;
+                i += 2;
+            } else {
+                i += 1;
+            }
+        }
